import { getActClass } from './utils';


export default {
  name: 'PressActInputQQ',
  options: {
    virtualHost: true,
    styleIsolation: 'shared',
  },
  props: {
    show: {
      type: Boolean,
      default: false,
      desc: '是否显示弹窗',
      required: false,
    },
    qqnumber: {
      type: String,
      default: '',
      desc: 'QQ号码',
      required: false,
    },
    useTipClass: {
      type: Boolean,
      default: false,
    },
    hideTipStyle: {
      type: Boolean,
      default: false,
    },
  },
  methods: {
    closeDialog() {
      this.$emit('update:show', false);
    },
    onClickButton() {
      this.$emit('clickButton');
    },
    changeQQnumber(e) {
      this.$emit('update:qqnumber', e.target.value);
    },
    getActClass(...args) {
      return getActClass(this.useTipClass, args);
    },
  },
};
